    43→func ProvideService(httpClientProvider *httpclient.Provider, tracer tracing.Tracer) *Service {
    44→	return &Service{
    45→		im:     datasource.NewInstanceManager(newInstanceSettings(httpClientProvider)),
    46→		tracer: tracer,
    47→		logger: backend.NewLoggerWith("logger", "tsdb.loki"),
    48→	}
