    88→func newInstanceSettings(httpClientProvider *httpclient.Provider) datasource.InstanceFactoryFunc {
    89→	return func(ctx context.Context, settings backend.DataSourceInstanceSettings) (instancemgmt.Instance, error) {
    90→		opts, err := settings.HTTPClientOptions(ctx)
    91→		if err != nil {
    92→			return nil, err
    93→		}
    94→		opts.ForwardHTTPHeaders = true
    95→
    96→		client, err := httpClientProvider.New(opts)
    97→		if err != nil {
    98→			return nil, err
    99→		}
   100→
   101→		model := &datasourceInfo{
   102→			HTTPClient: client,
   103→			URL:        settings.URL,
   104→			streams:    make(map[string]data.FrameJSONCache),
   105→		}
   106→		return model, nil
   107→	}
   108→}
