   152→func (s *Service) QueryData(ctx context.Context, req *backend.QueryDataRequest) (*backend.QueryDataResponse, error) {
   153→	dsInfo, err := s.getDSInfo(ctx, req.PluginContext)
   154→	_, fromAlert := req.Headers[ngalertmodels.FromAlertHeaderName]
   155→	logger := s.logger.FromContext(ctx).With("fromAlert", fromAlert)
   156→	if err != nil {
   157→		logger.Error("Failed to get data source info", "err", err)
   158→		result := backend.NewQueryDataResponse()
   159→		return result, err
   160→	}
   161→
   162→	responseOpts := ResponseOpts{
   163→		metricDataplane: isFeatureEnabled(ctx, featuremgmt.FlagLokiMetricDataplane),
   164→		logsDataplane:   isFeatureEnabled(ctx, featuremgmt.FlagLokiLogsDataplane),
   165→	}
   166→
   167→	if isFeatureEnabled(ctx, featuremgmt.FlagLokiSendDashboardPanelNames) {
   168→		s.applyHeaders(ctx, req)
   169→	}
   170→
   171→	return queryData(ctx, req, dsInfo, responseOpts, s.tracer, logger, isFeatureEnabled(ctx, featuremgmt.FlagLokiRunQueriesInParallel), isFeatureEnabled(ctx, featuremgmt.FlagLokiStructuredMetadata))
   172→}
