   174→func (s *Service) applyHeaders(ctx context.Context, req backend.ForwardHTTPHeaders) {
   175→	reqCtx := contexthandler.FromContext(ctx)
   176→	if req == nil || reqCtx == nil || reqCtx.Req == nil {
   177→		return
   178→	}
   179→
   180→	var hList = []string{dashboardTitleHeader, panelTitleHeader}
   181→
   182→	for _, hName := range hList {
   183→		hVal := reqCtx.Req.Header.Get(hName)
   184→		if hVal == "" {
   185→			continue
   186→		}
   187→		req.SetHTTPHeader(hName, hVal)
   188→	}
   189→}
