   191→func queryData(ctx context.Context, req *backend.QueryDataRequest, dsInfo *datasourceInfo, responseOpts ResponseOpts, tracer tracing.Tracer, plog log.Logger, runInParallel bool, requestStructuredMetadata bool) (*backend.QueryDataResponse, error) {
   192→	result := backend.NewQueryDataResponse()
   193→
   194→	api := newLokiAPI(dsInfo.HTTPClient, dsInfo.URL, plog, tracer, requestStructuredMetadata)
   195→
   196→	start := time.Now()
   197→	queries, err := parseQuery(req)
   198→	if err != nil {
   199→		plog.Error("Failed to prepare request to Loki", "error", err, "duration", time.Since(start), "queriesLength", len(queries), "stage", stagePrepareRequest)
   200→		return result, err
   201→	}
   202→
   203→	plog.Info("Prepared request to Loki", "duration", time.Since(start), "queriesLength", len(queries), "stage", stagePrepareRequest, "runInParallel", runInParallel)
   204→
   205→	ctx, span := tracer.Start(ctx, "datasource.loki.queryData.runQueries", trace.WithAttributes(
   206→		attribute.Bool("runInParallel", runInParallel),
   207→		attribute.Int("queriesLength", len(queries)),
   208→	))
   209→	if req.GetHTTPHeader("X-Query-Group-Id") != "" {
   210→		span.SetAttributes(attribute.String("query_group_id", req.GetHTTPHeader("X-Query-Group-Id")))
   211→	}
   212→	defer span.End()
   213→	start = time.Now()
   214→
   215→	// We are testing running of queries in parallel behind feature flag
   216→	if runInParallel {
   217→		resultLock := sync.Mutex{}
   218→		err = concurrency.ForEachJob(ctx, len(queries), 10, func(ctx context.Context, idx int) error {
   219→			query := queries[idx]
   220→			queryRes := executeQuery(ctx, query, req, runInParallel, api, responseOpts, tracer, plog)
   221→
   222→			resultLock.Lock()
   223→			defer resultLock.Unlock()
   224→			result.Responses[query.RefID] = queryRes
   225→			return nil // errors are saved per-query,always return nil
   226→		})
   227→	} else {
   228→		for _, query := range queries {
   229→			queryRes := executeQuery(ctx, query, req, runInParallel, api, responseOpts, tracer, plog)
   230→			result.Responses[query.RefID] = queryRes
   231→		}
   232→	}
   233→	plog.Debug("Executed queries", "duration", time.Since(start), "queriesLength", len(queries), "runInParallel", runInParallel)
   234→	return result, err
   235→}
   236→
   237→func executeQuery(ctx context.Context, query *lokiQuery, req *backend.QueryDataRequest, runInParallel bool, api *LokiAPI, responseOpts ResponseOpts, tracer tracing.Tracer, plog log.Logger) backend.DataResponse {
   238→	ctx, span := tracer.Start(ctx, "datasource.loki.queryData.runQueries.runQuery", trace.WithAttributes(
   239→		attribute.Bool("runInParallel", runInParallel),
   240→		attribute.String("expr", query.Expr),
   241→		attribute.Int64("start_unixnano", query.Start.UnixNano()),
   242→		attribute.Int64("stop_unixnano", query.End.UnixNano()),
   243→	))
   244→	if req.GetHTTPHeader("X-Query-Group-Id") != "" {
   245→		span.SetAttributes(attribute.String("query_group_id", req.GetHTTPHeader("X-Query-Group-Id")))
   246→	}
   247→
   248→	defer span.End()
   249→
   250→	queryRes, err := runQuery(ctx, api, query, responseOpts, plog)
   251→	if queryRes == nil {
   252→		// we always want to return a backend.DataResponse object, even if we received just an error
   253→		queryRes = &backend.DataResponse{}
   254→	}
   255→
   256→	if err != nil {
   257→		span.RecordError(err)
   258→		span.SetStatus(codes.Error, err.Error())
   259→		queryRes.Error = err
   260→	}
   261→
   262→	return *queryRes
   263→}
   264→
   265→// we extracted this part of the functionality to make it easy to unit-test it
   266→func runQuery(ctx context.Context, api *LokiAPI, query *lokiQuery, responseOpts ResponseOpts, plog log.Logger) (*backend.DataResponse, error) {
   267→	res, err := api.DataQuery(ctx, *query, responseOpts)
   268→	if err != nil {
   269→		plog.Error("Error querying loki", "error", err)
   270→		return res, err
   271→	}
   272→
   273→	for _, frame := range res.Frames {
   274→		err = adjustFrame(frame, query, !responseOpts.metricDataplane, responseOpts.logsDataplane)
   275→
   276→		if err != nil {
   277→			plog.Error("Error adjusting frame", "error", err)
   278→			return res, err
   279→		}
   280→	}
   281→
   282→	return res, nil
   283→}
   284→
   285→func (s *Service) getDSInfo(ctx context.Context, pluginCtx backend.PluginContext) (*datasourceInfo, error) {
   286→	i, err := s.im.Get(ctx, pluginCtx)
   287→	if err != nil {
   288→		return nil, err
   289→	}
   290→
   291→	instance, ok := i.(*datasourceInfo)
   292→	if !ok {
   293→		return nil, fmt.Errorf("failed to cast data source info")
   294→	}
   295→
   296→	return instance, nil
   297→}
   298→
   299→func isFeatureEnabled(ctx context.Context, feature string) bool {
   300→	return backend.GrafanaConfigFromContext(ctx).FeatureToggles().IsEnabled(feature)
   301→}
