    68→	case QueryTypeRange:
    69→		{
    70→			qs.Set("start", strconv.FormatInt(query.Start.UnixNano(), 10))
    71→			qs.Set("end", strconv.FormatInt(query.End.UnixNano(), 10))
    72→			// NOTE: technically for streams-producing queries `step`
    73→			// is ignored, so it would be nicer to not send it in such cases,
    74→			// but we cannot detect that situation, so we always send it.
    75→			// it should not break anything.
    76→			// NOTE2: we do this at millisecond precision for two reasons:
    77→			//  a. Loki cannot do steps with better precision anyway,
    78→			//     so the microsecond & nanosecond part can be ignored.
    79→			//  b. having it always be number+'ms' makes it more robust and
    80→			//     precise, as Loki does not support step with float number
    81→			//     and time-specifier, like "1.5s"
    82→			qs.Set("step", fmt.Sprintf("%dms", query.Step.Milliseconds()))
