   126→func makeLokiError(bytes []byte) error {
   127→	var data lokiError
   128→	err := json.Unmarshal(bytes, &data)
   129→	if err != nil {
   130→		// we were unable to convert the bytes to JSON, we return the whole text
   131→		return fmt.Errorf("%v", string(bytes))
   132→	}
   133→
   134→	if data.Message == "" {
   135→		// we got no usable error message, we return the whole text
   136→		return fmt.Errorf("%v", string(bytes))
   137→	}
   138→
   139→	return fmt.Errorf("%v", data.Message)
   140→}
   141→
   142→// we know there is an error,
   143→// based on the http-response-body
   144→// we have to make an informative error-object
   145→func readLokiError(body io.ReadCloser) error {
   146→	var buf bytes.Buffer
   147→	_, err := buf.ReadFrom(body)
   148→	if err != nil {
   149→		return err
   150→	}
   151→
   152→	bytes := buf.Bytes()
   153→
   154→	// the error-message is probably a JSON structure,
   155→	// with a string-field named "message". we want the
   156→	// value of that field.
   157→	// but, the response might be just a simple string,
   158→	// this was used in older Loki versions.
   159→	// so our approach is this:
   160→	// - we try to convert the bytes to JSON
   161→	// - we take the value of the field "message"
   162→	// - if any of these steps fail, or if "message" is empty, we return the whole text
   163→
   164→	return makeLokiError(bytes)
   165→}
