   309→	if resp.StatusCode/100 != 2 {
   310→		lokiResponseErr := lokiResponseError{Message: makeLokiError(body).Error()}
   311→		api.log.Warn("Non 200 HTTP status received from loki", "error", lokiResponseErr.Message, "statusCode", resp.StatusCode, "resourcePath", resourcePath)
