   322→	rawLokiResponse := RawLokiResponse{
   323→		Body:     body,
   324→		Status:   resp.StatusCode,
   325→		Encoding: resp.Header.Get("Content-Encoding"),
   326→	}
   327→
   328→	return rawLokiResponse, nil
