   657→// DecodeHTTPGrpcResponse decodes an httpgrp.HTTPResponse to queryrangebase.Response.
   658→func (Codec) DecodeHTTPGrpcResponse(r *httpgrpc.HTTPResponse, req queryrangebase.Request) (queryrangebase.Response, error) {
   659→	if r.Code/100 != 2 {
   660→		return nil, httpgrpc.Errorf(int(r.Code), "%s", string(r.Body))
   661→	}
   662→
   663→	headers := make(http.Header)
   664→	for _, header := range r.Headers {
   665→		headers[header.Key] = header.Values
   666→	}
   667→	return decodeResponseJSONFrom(r.Body, req, headers)
   668→}
