   670→func (Codec) EncodeHTTPGrpcResponse(_ context.Context, req *httpgrpc.HTTPRequest, res queryrangebase.Response) (*httpgrpc.HTTPResponse, error) {
   671→	version := loghttp.GetVersion(req.Url)
   672→	var buf bytes.Buffer
   673→
   674→	encodingFlags := httpreq.ExtractEncodingFlagsFromProto(req)
   675→
   676→	err := encodeResponseJSONTo(version, res, &buf, encodingFlags)
   677→	if err != nil {
   678→		return nil, err
   679→	}
   680→
   681→	httpRes := &httpgrpc.HTTPResponse{
   682→		Code: int32(http.StatusOK),
   683→		Body: buf.Bytes(),
   684→		Headers: []*httpgrpc.Header{
   685→			{Key: "Content-Type", Values: []string{"application/json; charset=UTF-8"}},
   686→		},
   687→	}
   688→
   689→	for _, h := range res.GetHeaders() {
   690→		httpRes.Headers = append(httpRes.Headers, &httpgrpc.Header{Key: h.Name, Values: h.Values})
   691→	}
   692→
   693→	return httpRes, nil
   694→}
