   672→	var buf bytes.Buffer
   673→
   674→	encodingFlags := httpreq.ExtractEncodingFlagsFromProto(req)
   675→
   676→	err := encodeResponseJSONTo(version, res, &buf, encodingFlags)
   677→	if err != nil {
   678→		return nil, err
   679→	}
   680→
   681→	httpRes := &httpgrpc.HTTPResponse{
   682→		Code: int32(http.StatusOK),
   683→		Body: buf.Bytes(),
   684→		Headers: []*httpgrpc.Header{
