   718→	// Add limits
   719→	if limits := querylimits.ExtractQueryLimitsContext(ctx); limits != nil {
   720→		err := querylimits.InjectQueryLimitsHeader(&header, limits)
   721→		if err != nil {
   722→			return nil, err
   723→		}
   724→	}
   725→
   726→	// Add org id
   727→	orgID, err := user.ExtractOrgID(ctx)
