   743→	case *LokiRequest:
   744→		params := url.Values{
   745→			"start":     []string{fmt.Sprintf("%d", request.StartTs.UnixNano())},
   746→			"end":       []string{fmt.Sprintf("%d", request.EndTs.UnixNano())},
   747→			"query":     []string{request.Query},
   748→			"direction": []string{request.Direction.String()},
