  1281→func (Codec) EncodeResponse(ctx context.Context, req *http.Request, res queryrangebase.Response) (*http.Response, error) {
  1282→	if req.Header.Get("Accept") == ProtobufType {
  1283→		return encodeResponseProtobuf(ctx, res)
  1284→	}
  1285→
  1286→	// Default to JSON.
  1287→	version := loghttp.GetVersion(req.RequestURI)
  1288→	encodingFlags := httpreq.ExtractEncodingFlags(req)
  1289→	return encodeResponseJSON(ctx, version, res, encodingFlags)
  1290→}
