  1292→func encodeResponseJSON(ctx context.Context, version loghttp.Version, res queryrangebase.Response, encodeFlags httpreq.EncodingFlags) (*http.Response, error) {
  1293→	sp, _ := opentracing.StartSpanFromContext(ctx, "codec.EncodeResponse")
  1294→	defer sp.Finish()
  1295→	var buf bytes.Buffer
  1296→
  1297→	err := encodeResponseJSONTo(version, res, &buf, encodeFlags)
  1298→	if err != nil {
  1299→		return nil, err
  1300→	}
  1301→
  1302→	sp.LogFields(otlog.Int("bytes", buf.Len()))
  1303→
  1304→	resp := http.Response{
  1305→		Header: http.Header{
  1306→			"Content-Type": []string{"application/json; charset=UTF-8"},
  1307→		},
  1308→		Body:       io.NopCloser(&buf),
  1309→		StatusCode: http.StatusOK,
  1310→	}
  1311→	return &resp, nil
  1312→}
