  1389→func encodeResponseProtobuf(ctx context.Context, res queryrangebase.Response) (*http.Response, error) {
  1390→	sp, _ := opentracing.StartSpanFromContext(ctx, "codec.EncodeResponse")
  1391→	defer sp.Finish()
  1392→
  1393→	p, err := QueryResponseWrap(res)
  1394→	if err != nil {
  1395→		return nil, httpgrpc.Errorf(http.StatusInternalServerError, "%s", err.Error())
  1396→	}
  1397→
  1398→	buf, err := p.Marshal()
  1399→	if err != nil {
  1400→		return nil, fmt.Errorf("could not marshal protobuf: %w", err)
  1401→	}
  1402→
  1403→	resp := http.Response{
  1404→		Header: http.Header{
  1405→			"Content-Type": []string{ProtobufType},
  1406→		},
  1407→		Body:       io.NopCloser(bytes.NewBuffer(buf)),
  1408→		StatusCode: http.StatusOK,
  1409→	}
  1410→	return &resp, nil
  1411→}
