  1605→// mergeOrderedNonOverlappingStreams merges a set of ordered, nonoverlapping responses by concatenating matching streams then running them through a heap to pull out limit values
  1606→func mergeOrderedNonOverlappingStreams(resps []*LokiResponse, limit uint32, direction logproto.Direction) []logproto.Stream {
  1607→	var total int
  1608→
  1609→	// turn resps -> map[labels] []entries
  1610→	groups := make(map[string]*byDir)
  1611→	for _, resp := range resps {
  1612→		for _, stream := range resp.Data.Result {
  1613→			s, ok := groups[stream.Labels]
  1614→			if !ok {
  1615→				s = &byDir{
  1616→					direction: direction,
  1617→					labels:    stream.Labels,
  1618→				}
  1619→				groups[stream.Labels] = s
  1620→			}
  1621→
  1622→			s.markers = append(s.markers, stream.Entries)
  1623→			total += len(stream.Entries)
  1624→		}
  1625→
  1626→		// optimization: since limit has been reached, no need to append entries from subsequent responses
  1627→		if total >= int(limit) {
  1628→			break
  1629→		}
  1630→	}
  1631→
  1632→	keys := make([]string, 0, len(groups))
  1633→	for key := range groups {
  1634→		keys = append(keys, key)
  1635→	}
  1636→	if direction == logproto.BACKWARD {
  1637→		sort.Sort(sort.Reverse(sort.StringSlice(keys)))
  1638→	} else {
  1639→		sort.Strings(keys)
  1640→	}
  1641→
  1642→	// escape hatch, can just return all the streams
  1643→	if total <= int(limit) {
  1644→		results := make([]logproto.Stream, 0, len(keys))
  1645→		for _, key := range keys {
  1646→			results = append(results, logproto.Stream{
  1647→				Labels:  key,
  1648→				Entries: groups[key].merge(),
  1649→			})
  1650→		}
  1651→		return results
  1652→	}
  1653→
  1654→	pq := &priorityqueue{
  1655→		direction: direction,
  1656→	}
  1657→
  1658→	for _, key := range keys {
  1659→		stream := &logproto.Stream{
  1660→			Labels:  key,
  1661→			Entries: groups[key].merge(),
  1662→		}
  1663→		if len(stream.Entries) > 0 {
  1664→			pq.streams = append(pq.streams, stream)
  1665→		}
  1666→	}
  1667→
  1668→	heap.Init(pq)
  1669→
  1670→	resultDict := make(map[string]*logproto.Stream)
  1671→
  1672→	// we want the min(limit, num_entries)
  1673→	for i := 0; i < int(limit) && pq.Len() > 0; i++ {
  1674→		// grab the next entry off the queue. This will be a stream (to preserve labels) with one entry.
  1675→		next := heap.Pop(pq).(*logproto.Stream)
  1676→
  1677→		s, ok := resultDict[next.Labels]
  1678→		if !ok {
  1679→			s = &logproto.Stream{
  1680→				Labels:  next.Labels,
  1681→				Entries: make([]logproto.Entry, 0, int(limit)/len(keys)), // allocation hack -- assume uniform distribution across labels
  1682→			}
  1683→			resultDict[next.Labels] = s
  1684→		}
  1685→		// TODO: make allocation friendly
  1686→		s.Entries = append(s.Entries, next.Entries...)
  1687→	}
  1688→
  1689→	results := make([]logproto.Stream, 0, len(resultDict))
  1690→	for _, key := range keys {
  1691→		stream, ok := resultDict[key]
  1692→		if ok {
  1693→			results = append(results, *stream)
  1694→		}
  1695→	}
  1696→
  1697→	return results
  1698→}
