  1762→func ParamsFromRequest(req queryrangebase.Request) (logql.Params, error) {
  1763→	switch r := req.(type) {
  1764→	case *LokiRequest:
  1765→		return &paramsRangeWrapper{
  1766→			LokiRequest: r,
  1767→		}, nil
  1768→	case *logproto.VolumeRequest:
  1769→		return &paramsRangeWrapper{
  1770→			LokiRequest: &LokiRequest{
  1771→				Query:   r.GetQuery(),
  1772→				Limit:   uint32(r.GetLimit()),
  1773→				Step:    r.GetStep(),
  1774→				StartTs: time.UnixMilli(r.GetStart().UnixNano()),
  1775→				EndTs:   time.UnixMilli(r.GetEnd().UnixNano()),
  1776→			},
  1777→		}, nil
  1778→	case *LokiInstantRequest:
  1779→		return &paramsInstantWrapper{
  1780→			LokiInstantRequest: r,
  1781→		}, nil
  1782→	case *LokiSeriesRequest:
  1783→		return &paramsSeriesWrapper{
  1784→			LokiSeriesRequest: r,
  1785→		}, nil
  1786→	case *LabelRequest:
  1787→		return &paramsLabelWrapper{
  1788→			LabelRequest: r,
  1789→		}, nil
  1790→	case *logproto.IndexStatsRequest:
  1791→		return &paramsStatsWrapper{
  1792→			IndexStatsRequest: r,
  1793→		}, nil
  1794→	case *DetectedFieldsRequest:
  1795→		return &paramsDetectedFieldsWrapper{
  1796→			DetectedFieldsRequest: r,
  1797→		}, nil
  1798→	case *DetectedLabelsRequest:
  1799→		return &paramsDetectedLabelsWrapper{
  1800→			DetectedLabelsRequest: r,
