  2176→func mergeLokiResponse(responses ...queryrangebase.Response) *LokiResponse {
  2177→	if len(responses) == 0 {
  2178→		return nil
  2179→	}
  2180→	var (
  2181→		lokiRes       = responses[0].(*LokiResponse)
  2182→		mergedStats   stats.Result
  2183→		lokiResponses = make([]*LokiResponse, 0, len(responses))
  2184→	)
  2185→
  2186→	uniqueWarnings := map[string]struct{}{}
  2187→	for _, res := range responses {
  2188→		lokiResult := res.(*LokiResponse)
  2189→		mergedStats.MergeSplit(lokiResult.Statistics)
  2190→		lokiResponses = append(lokiResponses, lokiResult)
  2191→
  2192→		for _, w := range lokiResult.Warnings {
  2193→			uniqueWarnings[w] = struct{}{}
  2194→		}
  2195→	}
  2196→
  2197→	warnings := maps.Keys(uniqueWarnings)
  2198→	sort.Strings(warnings)
  2199→
  2200→	if len(warnings) == 0 {
  2201→		// When there are no warnings, keep it nil so it can be compared against
  2202→		// the default value
  2203→		warnings = nil
  2204→	}
  2205→
  2206→	return &LokiResponse{
  2207→		Status:     loghttp.QueryStatusSuccess,
  2208→		Direction:  lokiRes.Direction,
  2209→		Limit:      lokiRes.Limit,
  2210→		Version:    lokiRes.Version,
  2211→		ErrorType:  lokiRes.ErrorType,
  2212→		Error:      lokiRes.Error,
  2213→		Statistics: mergedStats,
  2214→		Warnings:   warnings,
  2215→		Data: LokiData{
  2216→			ResultType: loghttp.ResultTypeStream,
  2217→			Result:     mergeOrderedNonOverlappingStreams(lokiResponses, lokiRes.Limit, lokiRes.Direction),
  2218→		},
  2219→	}
  2220→}
