  1232→func decodeResponseProtobuf(r *http.Response, req queryrangebase.Request) (queryrangebase.Response, error) {
  1233→	var buf []byte
  1234→	var err error
  1235→	if buffer, ok := r.Body.(Buffer); ok {
  1236→		buf = buffer.Bytes()
  1237→	} else {
  1238→		buf, err = io.ReadAll(r.Body)
  1239→		if err != nil {
  1240→			return nil, httpgrpc.Errorf(http.StatusInternalServerError, "error decoding response: %v", err)
  1241→		}
  1242→	}
  1243→
  1244→	// Shortcut series responses without deserialization.
  1245→	if _, ok := req.(*LokiSeriesRequest); ok {
  1246→		return GetLokiSeriesResponseView(buf)
  1247→	}
  1248→
  1249→	resp := &QueryResponse{}
  1250→	err = resp.Unmarshal(buf)
  1251→	if err != nil {
  1252→		return nil, httpgrpc.Errorf(http.StatusInternalServerError, "error decoding response: %v", err)
  1253→	}
  1254→
  1255→	headers := httpResponseHeadersToPromResponseHeaders(r.Header)
  1256→	switch req.(type) {
  1257→	case *LokiSeriesRequest:
  1258→		return resp.GetSeries().WithHeaders(headers), nil
  1259→	case *LabelRequest:
  1260→		return resp.GetLabels().WithHeaders(headers), nil
  1261→	case *logproto.IndexStatsRequest:
  1262→		return resp.GetStats().WithHeaders(headers), nil
  1263→	case *logproto.ShardsRequest:
  1264→		return resp.GetShardsResponse().WithHeaders(headers), nil
  1265→	default:
  1266→		switch concrete := resp.Response.(type) {
  1267→		case *QueryResponse_Prom:
  1268→			return concrete.Prom.WithHeaders(headers), nil
  1269→		case *QueryResponse_Streams:
  1270→			return concrete.Streams.WithHeaders(headers), nil
  1271→		case *QueryResponse_TopkSketches:
  1272→			return concrete.TopkSketches.WithHeaders(headers), nil
  1273→		case *QueryResponse_QuantileSketches:
  1274→			return concrete.QuantileSketches.WithHeaders(headers), nil
  1275→		default:
  1276→			return nil, httpgrpc.Errorf(http.StatusInternalServerError, "unsupported response type, got (%T)", resp.Response)
  1277→		}
  1278→	}
  1279→}
