  1314→func encodeResponseJSONTo(version loghttp.Version, res queryrangebase.Response, w io.Writer, encodeFlags httpreq.EncodingFlags) error {
  1315→	switch response := res.(type) {
  1316→	case *LokiPromResponse:
  1317→		return response.encodeTo(w)
  1318→	case *LokiResponse:
  1319→		streams := make([]logproto.Stream, len(response.Data.Result))
  1320→
  1321→		for i, stream := range response.Data.Result {
  1322→			streams[i] = logproto.Stream{
  1323→				Labels:  stream.Labels,
  1324→				Entries: stream.Entries,
  1325→			}
  1326→		}
  1327→		if version == loghttp.VersionLegacy {
  1328→			result := logqlmodel.Result{
  1329→				Data:       logqlmodel.Streams(streams),
  1330→				Statistics: response.Statistics,
  1331→			}
  1332→			if err := marshal_legacy.WriteQueryResponseJSON(result, w); err != nil {
  1333→				return err
  1334→			}
  1335→		} else {
  1336→			if err := marshal.WriteQueryResponseJSON(logqlmodel.Streams(streams), response.Warnings, response.Statistics, w, encodeFlags); err != nil {
  1337→				return err
  1338→			}
  1339→		}
  1340→	case *MergedSeriesResponseView:
  1341→		if err := WriteSeriesResponseViewJSON(response, w); err != nil {
  1342→			return err
  1343→		}
  1344→	case *LokiSeriesResponse:
  1345→		if err := marshal.WriteSeriesResponseJSON(response.Data, w); err != nil {
  1346→			return err
  1347→		}
  1348→	case *LokiLabelNamesResponse:
  1349→		if loghttp.Version(response.Version) == loghttp.VersionLegacy {
  1350→			if err := marshal_legacy.WriteLabelResponseJSON(logproto.LabelResponse{Values: response.Data}, w); err != nil {
  1351→				return err
  1352→			}
  1353→		} else {
  1354→			if err := marshal.WriteLabelResponseJSON(response.Data, w); err != nil {
  1355→				return err
  1356→			}
  1357→		}
  1358→	case *IndexStatsResponse:
  1359→		if err := marshal.WriteIndexStatsResponseJSON(response.Response, w); err != nil {
  1360→			return err
  1361→		}
  1362→	case *ShardsResponse:
  1363→		if err := marshal.WriteIndexShardsResponseJSON(response.Response, w); err != nil {
  1364→			return err
  1365→		}
  1366→	case *VolumeResponse:
  1367→		if err := marshal.WriteVolumeResponseJSON(response.Response, w); err != nil {
  1368→			return err
  1369→		}
  1370→	case *DetectedFieldsResponse:
  1371→		if err := marshal.WriteDetectedFieldsResponseJSON(response.Response, w); err != nil {
  1372→			return err
  1373→		}
  1374→	case *QueryPatternsResponse:
  1375→		if err := marshal.WriteQueryPatternsResponseJSON(response.Response, w); err != nil {
  1376→			return err
  1377→		}
  1378→	case *DetectedLabelsResponse:
  1379→		if err := marshal.WriteDetectedLabelsResponseJSON(response.Response, w); err != nil {
  1380→			return err
  1381→		}
  1382→	default:
  1383→		return httpgrpc.Errorf(http.StatusInternalServerError, "%s", fmt.Sprintf("invalid response format, got (%T)", res))
