  1413→// NOTE: When we would start caching response from non-metric queries we would have to consider cache gen headers as well in
  1414→// MergeResponse implementation for Loki codecs same as it is done in Cortex at https://github.com/cortexproject/cortex/blob/21bad57b346c730d684d6d0205efef133422ab28/pkg/querier/queryrange/query_range.go#L170
  1415→func (Codec) MergeResponse(responses ...queryrangebase.Response) (queryrangebase.Response, error) {
  1416→	if len(responses) == 0 {
  1417→		return nil, errors.New("merging responses requires at least one response")
  1418→	}
  1419→	var mergedStats stats.Result
  1420→	switch res := responses[0].(type) {
  1421→	// LokiPromResponse type is used for both instant and range queries.
  1422→	// Meaning, values that are merged can be either vector or matrix types.
  1423→	case *LokiPromResponse:
  1424→
  1425→		codec := queryrangebase.PrometheusCodecForRangeQueries
  1426→		if res.Response.Data.ResultType == model.ValVector.String() {
  1427→			codec = queryrangebase.PrometheusCodecForInstantQueries
  1428→		}
  1429→
  1430→		promResponses := make([]queryrangebase.Response, 0, len(responses))
  1431→		for _, res := range responses {
  1432→			mergedStats.MergeSplit(res.(*LokiPromResponse).Statistics)
  1433→			promResponses = append(promResponses, res.(*LokiPromResponse).Response)
  1434→		}
  1435→		promRes, err := codec.MergeResponse(promResponses...)
  1436→		if err != nil {
  1437→			return nil, err
  1438→		}
  1439→		return &LokiPromResponse{
  1440→			Response:   promRes.(*queryrangebase.PrometheusResponse),
  1441→			Statistics: mergedStats,
  1442→		}, nil
  1443→	case *LokiResponse:
  1444→		return mergeLokiResponse(responses...), nil
  1445→	case *LokiSeriesResponse:
  1446→		lokiSeriesRes := responses[0].(*LokiSeriesResponse)
  1447→
  1448→		var lokiSeriesData []logproto.SeriesIdentifier
  1449→		uniqueSeries := make(map[uint64]struct{})
  1450→
  1451→		// The buffers are used by `series.Hash`. They are allocated
  1452→		// outside of the method in order to reuse them for the next
  1453→		// iteration. This saves a lot of allocations.
  1454→		// 1KB is used for `b` after some experimentation. The
  1455→		// benchmarks are ~10% faster in comparison to no buffer with
  1456→		// little overhead. A run with 4MB should the same speedup but
  1457→		// much much more overhead.
  1458→		b := make([]byte, 0, 1024)
  1459→		var key uint64
  1460→
  1461→		// only unique series should be merged
  1462→		for _, res := range responses {
  1463→			lokiResult := res.(*LokiSeriesResponse)
  1464→			mergedStats.MergeSplit(lokiResult.Statistics)
  1465→			for _, series := range lokiResult.Data {
  1466→				// Use series hash as the key.
  1467→				key = series.Hash(b)
  1468→
  1469→				// TODO(karsten): There is a chance that the
  1470→				// keys match but not the labels due to hash
  1471→				// collision. Ideally there's an else block the
  1472→				// compares the series labels. However, that's
  1473→				// not trivial. Besides, instance.Series has the
  1474→				// same issue in its deduping logic.
  1475→				if _, ok := uniqueSeries[key]; !ok {
  1476→					lokiSeriesData = append(lokiSeriesData, series)
  1477→					uniqueSeries[key] = struct{}{}
  1478→				}
  1479→			}
  1480→		}
  1481→
  1482→		return &LokiSeriesResponse{
  1483→			Status:     lokiSeriesRes.Status,
  1484→			Version:    lokiSeriesRes.Version,
  1485→			Data:       lokiSeriesData,
  1486→			Headers:    lokiSeriesRes.Headers,
  1487→			Statistics: mergedStats,
  1488→		}, nil
  1489→	case *LokiSeriesResponseView:
  1490→		v := &MergedSeriesResponseView{}
  1491→		for _, r := range responses {
  1492→			v.responses = append(v.responses, r.(*LokiSeriesResponseView))
  1493→		}
  1494→		return v, nil
  1495→	case *MergedSeriesResponseView:
  1496→		v := &MergedSeriesResponseView{}
  1497→		for _, r := range responses {
  1498→			v.responses = append(v.responses, r.(*MergedSeriesResponseView).responses...)
  1499→		}
  1500→		return v, nil
  1501→	case *LokiLabelNamesResponse:
  1502→		labelNameRes := responses[0].(*LokiLabelNamesResponse)
  1503→		uniqueNames := make(map[string]struct{})
  1504→		names := []string{}
  1505→
  1506→		// only unique name should be merged
  1507→		for _, res := range responses {
  1508→			lokiResult := res.(*LokiLabelNamesResponse)
  1509→			mergedStats.MergeSplit(lokiResult.Statistics)
  1510→			for _, labelName := range lokiResult.Data {
  1511→				if _, ok := uniqueNames[labelName]; !ok {
  1512→					names = append(names, labelName)
  1513→					uniqueNames[labelName] = struct{}{}
  1514→				}
  1515→			}
  1516→		}
  1517→
  1518→		return &LokiLabelNamesResponse{
  1519→			Status:     labelNameRes.Status,
  1520→			Version:    labelNameRes.Version,
  1521→			Headers:    labelNameRes.Headers,
  1522→			Data:       names,
  1523→			Statistics: mergedStats,
  1524→		}, nil
  1525→	case *IndexStatsResponse:
  1526→		headers := responses[0].(*IndexStatsResponse).Headers
  1527→		stats := make([]*indexStats.Stats, len(responses))
  1528→		for i, res := range responses {
  1529→			stats[i] = res.(*IndexStatsResponse).Response
  1530→		}
  1531→
  1532→		mergedIndexStats := indexStats.MergeStats(stats...)
  1533→
  1534→		return &IndexStatsResponse{
  1535→			Response: &mergedIndexStats,
  1536→			Headers:  headers,
  1537→		}, nil
  1538→	case *VolumeResponse:
  1539→		resp0 := responses[0].(*VolumeResponse)
  1540→		headers := resp0.Headers
  1541→
  1542→		resps := make([]*logproto.VolumeResponse, 0, len(responses))
  1543→		for _, r := range responses {
  1544→			resps = append(resps, r.(*VolumeResponse).Response)
  1545→		}
  1546→
  1547→		return &VolumeResponse{
  1548→			Response: seriesvolume.Merge(resps, resp0.Response.Limit),
  1549→			Headers:  headers,
  1550→		}, nil
  1551→	case *DetectedFieldsResponse:
  1552→		resp0 := responses[0].(*DetectedFieldsResponse)
  1553→		headers := resp0.Headers
  1554→		limit := resp0.Response.GetLimit()
  1555→
  1556→		fields := []*logproto.DetectedField{}
  1557→		values := []string{}
  1558→		for _, r := range responses {
  1559→			fields = append(fields, r.(*DetectedFieldsResponse).Response.Fields...)
  1560→			values = append(values, r.(*DetectedFieldsResponse).Response.Values...)
  1561→		}
  1562→
  1563→		mergedFields, err := detected.MergeFields(fields, limit)
  1564→		if err != nil {
  1565→			return nil, err
  1566→		}
  1567→
  1568→		mergedValues, err := detected.MergeValues(values, limit)
  1569→		if err != nil {
  1570→			return nil, err
  1571→		}
  1572→
  1573→		return &DetectedFieldsResponse{
  1574→			Response: &logproto.DetectedFieldsResponse{
  1575→				Fields: mergedFields,
  1576→				Values: mergedValues,
  1577→				Limit:  limit,
  1578→			},
  1579→			Headers: headers,
  1580→		}, nil
  1581→	case *DetectedLabelsResponse:
  1582→		resp0 := responses[0].(*DetectedLabelsResponse)
  1583→		headers := resp0.Headers
  1584→		var labels []*logproto.DetectedLabel
  1585→
  1586→		for _, r := range responses {
  1587→			labels = append(labels, r.(*DetectedLabelsResponse).Response.DetectedLabels...)
  1588→		}
  1589→		mergedLabels, err := detected.MergeLabels(labels)
  1590→		if err != nil {
  1591→			return nil, err
  1592→		}
  1593→
  1594→		return &DetectedLabelsResponse{
  1595→			Response: &logproto.DetectedLabelsResponse{
  1596→				DetectedLabels: mergedLabels,
  1597→			},
  1598→			Headers: headers,
  1599→		}, nil
  1600→	default:
  1601→		return nil, fmt.Errorf("unknown response type (%T) in merging responses", responses[0])
  1602→	}
  1603→}
