  1700→func toProtoMatrix(m loghttp.Matrix) []queryrangebase.SampleStream {
  1701→	res := make([]queryrangebase.SampleStream, 0, len(m))
  1702→
  1703→	if len(m) == 0 {
  1704→		return res
  1705→	}
  1706→
  1707→	for _, stream := range m {
  1708→		samples := make([]logproto.LegacySample, 0, len(stream.Values))
  1709→		for _, s := range stream.Values {
  1710→			samples = append(samples, logproto.LegacySample{
  1711→				Value:       float64(s.Value),
  1712→				TimestampMs: int64(s.Timestamp),
  1713→			})
  1714→		}
  1715→		res = append(res, queryrangebase.SampleStream{
  1716→			Labels:  logproto.FromMetricsToLabelAdapters(stream.Metric),
  1717→			Samples: samples,
  1718→		})
  1719→	}
  1720→	return res
  1721→}
  1722→
  1723→func toProtoVector(v loghttp.Vector) []queryrangebase.SampleStream {
  1724→	res := make([]queryrangebase.SampleStream, 0, len(v))
  1725→
  1726→	if len(v) == 0 {
