  1728→	}
  1729→	for _, s := range v {
  1730→		res = append(res, queryrangebase.SampleStream{
  1731→			Samples: []logproto.LegacySample{{
  1732→				Value:       float64(s.Value),
  1733→				TimestampMs: int64(s.Timestamp),
  1734→			}},
  1735→			Labels: logproto.FromMetricsToLabelAdapters(s.Metric),
  1736→		})
